        "phoenix": {"port": None, "project_name": "test"},
        "mlflow": {"tracking_uri": "sqlite:///mlflow.db"}
    },
    "vector_store": {"host": "localhost", "http_port": 6333},
    "checkpointing": {"backend": "postgres", "database": "hcgrc"},
}

try:
    result = _validate_config(cfg_none, "test")
    print("BUG FOUND: Validation passed with port=None")
    print(f"  phoenix.port type: {type(result['observability']['phoenix']['port'])}")
except ConfigError:
    print("OK: Validation correctly rejected None")

# Test: Invalid backend value - should fail but doesn't
print("\n=== Test 2: Invalid backend value ===")
cfg_bad_backend = {
    "observability": {
        "phoenix": {"port": 6006, "project_name": "test"},
        "mlflow": {"tracking_uri": "sqlite:///mlflow.db"}
    },
    "vector_store": {"host": "localhost", "http_port": 6333},
    "checkpointing": {"backend": "unsupported_backend", "database": "hcgrc"},
}

try:
    result = _validate_config(cfg_bad_backend, "test")
    print("BUG FOUND: Validation passed with invalid backend value")
    print(f"  backend: {result['checkpointing']['backend']}")
except ConfigError:
    print("OK: Validation correctly rejected invalid backend")

# Test: Missing port for checkpointing - should it be required?
print("\n=== Test 3: Missing port in checkpointing ===")
cfg_no_port = {
    "observability": {
        "phoenix": {"port": 6006, "project_name": "test"},
